    private static readonly FrozenDictionary<int, char> ExponentToSymbol =
        new Dictionary<int, char>
        {
            [3] = 'k', [6] = 'M', [9] = 'G', [12] = 'T', [15] = 'P', [18] = 'E', [21] = 'Z', [24] = 'Y',
            [-3] = 'm', [-6] = 'μ', [-9] = 'n', [-12] = 'p', [-15] = 'f', [-18] = 'a', [-21] = 'z', [-24] = 'y',
        }.ToFrozenDictionary();

    // O(1) name→symbol lookup replaces the O(n) Aggregate + Replace chain in ReplaceNameBySymbol
    private static readonly FrozenDictionary<string, string> NameToSymbolString =
        UnitPrefixes.ToFrozenDictionary(
            kvp => kvp.Value.Name,
            kvp => kvp.Key.ToString());

    // Pre-cached symbol strings to avoid repeated char.ToString() allocations
    private static readonly FrozenDictionary<char, string> SymbolStrings =
        UnitPrefixes.ToFrozenDictionary(
            kvp => kvp.Key,
            kvp => kvp.Key.ToString());

    // Precomputed powers of 10 to avoid Math.Pow in hot paths
    private static readonly FrozenDictionary<int, double> PowersOf10 =
        ExponentToSymbol.Keys.ToFrozenDictionary(e => e, e => Math.Pow(10, e));

    /// <summary>
    /// Converts a number to its metric representation using the specified formatting options.
    /// </summary>
    /// <param name="input">The number to convert.</param>
    /// <param name="formats">Formatting options controlling symbol vs name and scale.</param>
    /// <param name="decimals">Optional number of decimal places to round to.</param>
